// ============================================================
// HydraNet - Branches API Route
// ============================================================

import { NextRequest, NextResponse } from 'next/server'
import prisma from '@/lib/prisma'
import { EntityStatus } from '@prisma/client'

// GET /api/branches - List all branches (filtered by DMA for DMA managers)
export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url)
    const dmaId = searchParams.get('dmaId')
    const utilityId = searchParams.get('utilityId')

    const branches = await prisma.branch.findMany({
      where: {
        ...(dmaId ? { dmaId } : {}),
        ...(utilityId ? { utilityId } : {}),
      },
      include: {
        dma: { select: { id: true, name: true } },
        utility: { select: { id: true, name: true } },
        _count: {
          select: {
            engineers: true,
            teams: true,
            reports: true,
          },
        },
      },
      orderBy: { name: 'asc' },
    })

    const formattedBranches = branches.map((branch) => ({
      id: branch.id,
      name: branch.name,
      description: branch.description,
      dmaId: branch.dmaId,
      dmaName: branch.dma.name,
      utilityId: branch.utilityId,
      utilityName: branch.utility.name,
      status: branch.status,
      engineerCount: branch._count.engineers,
      teamCount: branch._count.teams,
      reportCount: branch._count.reports,
      createdAt: branch.createdAt,
      updatedAt: branch.updatedAt,
    }))

    return NextResponse.json(formattedBranches)
  } catch (error) {
    console.error('Error fetching branches:', error)
    return NextResponse.json({ error: 'Failed to fetch branches' }, { status: 500 })
  }
}

// POST /api/branches - Create a new branch
export async function POST(request: NextRequest) {
  try {
    const data = await request.json()

    // Validate required fields
    if (!data.name || !data.dmaId || !data.utilityId) {
      return NextResponse.json(
        { error: 'Name, DMA ID, and Utility ID are required' },
        { status: 400 }
      )
    }

    // Check if branch with same name already exists in this DMA
    const existingBranch = await prisma.branch.findFirst({
      where: {
        name: data.name,
        dmaId: data.dmaId,
      },
    })

    if (existingBranch) {
      return NextResponse.json(
        { error: 'A branch with this name already exists in this DMA' },
        { status: 400 }
      )
    }

    const branch = await prisma.branch.create({
      data: {
        name: data.name,
        description: data.description || null,
        dmaId: data.dmaId,
        utilityId: data.utilityId,
        status: data.status || 'active',
      },
      include: {
        dma: { select: { id: true, name: true } },
        utility: { select: { id: true, name: true } },
        _count: {
          select: {
            engineers: true,
            teams: true,
            reports: true,
          },
        },
      },
    })

    return NextResponse.json({
      id: branch.id,
      name: branch.name,
      description: branch.description,
      dmaId: branch.dmaId,
      dmaName: branch.dma.name,
      utilityId: branch.utilityId,
      utilityName: branch.utility.name,
      status: branch.status,
      engineerCount: branch._count.engineers,
      teamCount: branch._count.teams,
      reportCount: branch._count.reports,
      createdAt: branch.createdAt,
      updatedAt: branch.updatedAt,
    }, { status: 201 })
  } catch (error) {
    console.error('Error creating branch:', error)
    return NextResponse.json({ error: 'Failed to create branch' }, { status: 500 })
  }
}

// PUT /api/branches - Update a branch
export async function PUT(request: NextRequest) {
  try {
    const data = await request.json()

    if (!data.id) {
      return NextResponse.json({ error: 'Branch ID is required' }, { status: 400 })
    }

    // Check if branch exists
    const existingBranch = await prisma.branch.findUnique({
      where: { id: data.id },
    })

    if (!existingBranch) {
      return NextResponse.json({ error: 'Branch not found' }, { status: 404 })
    }

    // Check if new name conflicts with another branch in the same DMA
    if (data.name && data.name !== existingBranch.name) {
      const nameConflict = await prisma.branch.findFirst({
        where: {
          name: data.name,
          dmaId: existingBranch.dmaId,
          id: { not: data.id },
        },
      })

      if (nameConflict) {
        return NextResponse.json(
          { error: 'A branch with this name already exists in this DMA' },
          { status: 400 }
        )
      }
    }

    const branch = await prisma.branch.update({
      where: { id: data.id },
      data: {
        name: data.name,
        description: data.description !== undefined ? data.description : existingBranch.description,
        status: data.status as EntityStatus,
      },
      include: {
        dma: { select: { id: true, name: true } },
        utility: { select: { id: true, name: true } },
        _count: {
          select: {
            engineers: true,
            teams: true,
            reports: true,
          },
        },
      },
    })

    return NextResponse.json({
      id: branch.id,
      name: branch.name,
      description: branch.description,
      dmaId: branch.dmaId,
      dmaName: branch.dma.name,
      utilityId: branch.utilityId,
      utilityName: branch.utility.name,
      status: branch.status,
      engineerCount: branch._count.engineers,
      teamCount: branch._count.teams,
      reportCount: branch._count.reports,
      createdAt: branch.createdAt,
      updatedAt: branch.updatedAt,
    })
  } catch (error) {
    console.error('Error updating branch:', error)
    return NextResponse.json({ error: 'Failed to update branch' }, { status: 500 })
  }
}

// DELETE /api/branches - Delete a branch
export async function DELETE(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url)
    const id = searchParams.get('id')

    if (!id) {
      return NextResponse.json({ error: 'Branch ID is required' }, { status: 400 })
    }

    // Check if branch has associated data
    const branch = await prisma.branch.findUnique({
      where: { id },
      include: {
        _count: {
          select: {
            engineers: true,
            teams: true,
            reports: true,
          },
        },
      },
    })

    if (!branch) {
      return NextResponse.json({ error: 'Branch not found' }, { status: 404 })
    }

    // Check if branch has associated data
    if (branch._count.engineers > 0) {
      return NextResponse.json(
        { error: 'Cannot delete branch with assigned engineers. Please reassign or delete them first.' },
        { status: 400 }
      )
    }

    if (branch._count.teams > 0) {
      return NextResponse.json(
        { error: 'Cannot delete branch with assigned teams. Please reassign or delete them first.' },
        { status: 400 }
      )
    }

    if (branch._count.reports > 0) {
      return NextResponse.json(
        { error: 'Cannot delete branch with associated reports.' },
        { status: 400 }
      )
    }

    await prisma.branch.delete({
      where: { id },
    })

    return NextResponse.json({ success: true })
  } catch (error) {
    console.error('Error deleting branch:', error)
    return NextResponse.json({ error: 'Failed to delete branch' }, { status: 500 })
  }
}